mapper.insert:

INSERT INTO CERT_USER_TABLE
(
	CERT_SEQ
	, USER_ID
	, IS_CORPORATION
	, CERT_CN
	, CERT_DN
	, CERT_OU
	, BEFORE_DATE
	, AFTER_DATE
	, BCID
	, CERT_STATUS
	, IRS_NUM

	, DI

)
VALUES
(
	CERT_AUTO_SEQ.nextval
	, #{userId}
	, #{isCorporation}
	, #{signCertCn}
	, #{signCertDn}
	, #{signCertOu}
	, #{beforeDate}
	, #{afterDate}
	, #{bcid}
	, #{certStatus}
	, #{irsNo}

	, #{di}

)

mapper.select:
SELECT COUNT(*) AS CountUser FROM CERT_USER_TABLE WHERE CERT_STATUS='validity' AND IS_CORPORATION=#{isCorporation} AND USER_ID=#{userId}
AND BCID = #{bcid}
ORDER BY CERT_SEQ DESC

SELECT ROWNUM AS NUM , CERTUSER.BCID , CASE CERTUSER.IS_CORPORATION WHEN 'true' THEN '법인용' WHEN 'false' THEN '개인용' ELSE '' END AS IS_CORPORATION , CERTUSER.CERT_CN , CERTUSER.CERT_OU , CASE CERTUSER.CERT_STATUS WHEN 'validity' THEN '유효' else '폐기' end as CERT_STATUS , SUBSTR(CERTUSER.BEFORE_DATE, 0, 4)||'-'||SUBSTR(CERTUSER.BEFORE_DATE, 5, 2)||'-'||SUBSTR(CERTUSER.BEFORE_DATE, 7, 2) || '~' || SUBSTR(CERTUSER.AFTER_DATE, 0, 4)||'-'||SUBSTR(CERTUSER.AFTER_DATE, 5, 2)||'-'||SUBSTR(CERTUSER.AFTER_DATE, 7, 2) AS CERT_DATE FROM CERT_USER_TABLE CERTUSER WHERE CERT_STATUS = 'validity' AND USER_ID=#{userId}
AND IS_CORPORATION = #{isCorporation}
ORDER BY cert_seq DESC

SELECT a.USER_ID , a.IS_CORPORATION , a.BCID , a.CERT_STATUS , b.COMPANY_CD , c.IRS_NUM FROM CERT_USER_TABLE a LEFT OUTER JOIN STOCCVUR b ON a.USER_ID = b.USER_ID LEFT OUTER JOIN STOCCUST c ON b.COMPANY_CD = c.CUST_CD WHERE a.USER_ID = b.USER_ID AND b.COMPANY_CD = c.CUST_CD AND a.CERT_STATUS = 'validity' AND IS_CORPORATION = #{isCorporation}
AND a.USER_ID = #{userId}
AND b.COMPANY_CD IN ( SELECT company_cd FROM STOCCVUR WHERE USER_ID=#{userId} )
